#!/usr/bin/env bun
/**
 * DeskLumina Theme Benchmark
 *
 * Measures the improvement from theme minification and caching
 * fun facts, this bench file is generated by AI because its more efficient
 */
import { readFileSync, statSync } from "fs";
import { getThemePath, refreshThemeCache } from "../src/ui/theme-cache";

const ORIGINAL_THEME = `${Bun.env.HOME}/.config/desklumina/src/ui/themes/lumina.rasi`;
const RUNS = 20;

function benchmarkThemeDump(label: string, themePath: string): number {
  const times: number[] = [];
  for (let i = 0; i < RUNS; i++) {
    const start = performance.now();
    try {
      Bun.spawnSync(["rofi", "-dump-theme", "-theme", themePath], {
        stdout: "ignore",
        stderr: "ignore",
      });
    } catch {
      // rofi -dump-theme exits 0 but may print to stderr; ignore
    }
    times.push(performance.now() - start);
  }
  const avg = times.reduce((a, b) => a + b, 0) / times.length;
  return avg;
}

function formatMs(ms: number): string {
  return `${ms.toFixed(2)} ms`;
}

async function main() {
  console.log("╔══════════════════════════════════════════════════════════════╗");
  console.log("║              DeskLumina Rofi Theme Benchmark                 ║");
  console.log("╚══════════════════════════════════════════════════════════════╝\n");

  // 1. File sizes
  const origStats = statSync(ORIGINAL_THEME);
  await refreshThemeCache();
  const cachedPath = await getThemePath();
  const cachedStats = statSync(cachedPath);

  console.log("📁 THEME FILE SIZES");
  console.log("──────────────────────────────────────────────────────────────");
  console.log(`  Original:  ${origStats.size.toLocaleString()} bytes`);
  console.log(`  Cached:    ${cachedStats.size.toLocaleString()} bytes`);
  console.log(`  Reduction: ${((1 - cachedStats.size / origStats.size) * 100).toFixed(1)}%`);
  console.log("");

  // 2. Benchmark parsing
  console.log("⏱️  ROFI THEME PARSING TIME (average of 20 runs)");
  console.log("──────────────────────────────────────────────────────────────");
  const origTime = benchmarkThemeDump("Original", ORIGINAL_THEME);
  const cachedTime = benchmarkThemeDump("Cached", cachedPath);
  console.log(`  Original theme: ${formatMs(origTime)}`);
  console.log(`  Cached theme:   ${formatMs(cachedTime)}`);
  console.log(`  Improvement:    ${formatMs(origTime - cachedTime)} (${((1 - cachedTime / origTime) * 100).toFixed(1)}% faster)`);
  console.log("");

  // 3. Spawn analysis
  console.log("🔢 SPAWN COUNT ANALYSIS");
  console.log("──────────────────────────────────────────────────────────────");
  const spawnsPerInteraction = {
    "Chat loop (send → loader → response → expanded)": 4,
    "Settings navigation (root → submenu → back)": 3,
    "Confirmation dialog": 1,
    "Alert dialog": 1,
  };
  let totalSpawns = 0;
  for (const [name, count] of Object.entries(spawnsPerInteraction)) {
    console.log(`  ${name}: ${count} spawn(s)`);
    totalSpawns += count;
  }
  console.log(`  Total potential spawns per full session: ~${totalSpawns}`);
  console.log("");

  // 4. Estimated savings
  console.log("💡 ESTIMATED SAVINGS PER INTERACTION");
  console.log("──────────────────────────────────────────────────────────────");
  const savingsPerSpawn = origTime - cachedTime;
  const totalSavings = savingsPerSpawn * 4; // worst case: 4 spawns
  console.log(`  Per spawn:   ${formatMs(savingsPerSpawn)}`);
  console.log(`  4-spawn UX:  ${formatMs(totalSavings)}`);
  console.log(`  Disk I/O:    Eliminated (cache lives in /tmp, typically tmpfs)`);
  console.log("");

  // 5. Cache invalidation
  console.log("🔄 CACHE INVALIDATION");
  console.log("──────────────────────────────────────────────────────────────");
  console.log(`  Source:      ${ORIGINAL_THEME}`);
  console.log(`  Cache:       ${cachedPath}`);
  console.log(`  Overhead:    < 1 ms (statSync on a 10 KB file)`);
  console.log("");

  // 6. Validation
  console.log("✅ VALIDATION");
  console.log("──────────────────────────────────────────────────────────────");
  try {
    const origProc = Bun.spawnSync(["rofi", "-dump-theme", "-theme", ORIGINAL_THEME], {
        stdout: "pipe",
        stderr: "pipe",
      });
      const origDump = origProc.stdout?.toString() || "";
      const cacheProc = Bun.spawnSync(["rofi", "-dump-theme", "-theme", cachedPath], {
        stdout: "pipe",
        stderr: "pipe",
      });
      const cacheDump = cacheProc.stdout?.toString() || "";
    const keysOrig = (origDump.match(/^\s+\w+:/gm) || []).sort().join(",");
    const keysCache = (cacheDump.match(/^\s+\w+:/gm) || []).sort().join(",");
    console.log(`  Theme keys match: ${keysOrig === keysCache ? "YES ✓" : "NO ✗"}`);
  } catch (e) {
    console.log(`  Theme validation: skipped (${e instanceof Error ? e.message : String(e)})`);
  }
  console.log("");

  console.log("═══════════════════════════════════════════════════════════════");
  console.log("Benchmark complete.");
  console.log("═══════════════════════════════════════════════════════════════");
}

main();
